import java.io.IOException;

public class CommandInjectionVulnerability {

    public static void main(String[] args) {
        String userInput = "example.txt; rm -rf /";

        try {
            Process process = Runtime.getRuntime().exec("cat " + userInput);
            // The above line is vulnerable to command injection as it directly concatenates user input to the command

            process.waitFor();
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}

